"""
T2 Blog -- Tag Routes (Sample 1: Decorator Pipeline Variant)

Implementation strategy: "Pure-function handlers + response-shaping decorators"

Instead of the typical pattern where each route handler calls jsonify() and
sets status codes inline, every handler is a *pure function* that returns a
(result_type, payload) tuple.  A single @tag_endpoint decorator transforms
that tuple into the correct Flask response.

This separates *what* the route does (business logic) from *how* it responds
(HTTP mechanics), making the handlers trivially testable as plain Python
functions without a Flask app context.

Author: Gen 1 Sample 1 -- Evolutionary PM
"""

from functools import wraps
from flask import Blueprint, jsonify, request

from models import db, Tag, article_tags

tag_bp = Blueprint('tag_bp', __name__)

# ------------------------------------------------------------------
# Result types -- a tiny algebraic-datatype-like enum
# ------------------------------------------------------------------
OK = "ok"
ERR_NOT_FOUND = "err_not_found"
ERR_BAD_REQUEST = "err_bad_request"
ERR_CONFLICT = "err_conflict"

# Mapping from result type to HTTP status code
_STATUS_MAP = {
    OK: 200,
    ERR_NOT_FOUND: 404,
    ERR_BAD_REQUEST: 400,
    ERR_CONFLICT: 409,
}

# For routes that should return 201 on success
_CREATED_ROUTES = {"create_tag"}


# ------------------------------------------------------------------
# Core decorator: tag_endpoint
# ------------------------------------------------------------------
def tag_endpoint(func):
    """Decorator that converts a (result_type, payload) tuple into a Flask
    JSON response with the correct status code.

    The wrapped function *must* return one of:
        (OK, data_dict_or_list)
        (ERR_BAD_REQUEST, error_message_str)
        (ERR_NOT_FOUND, error_message_str)
        (ERR_CONFLICT, error_message_str)

    Usage::

        @tag_bp.route("/tags", methods=["POST"])
        @tag_endpoint
        def create_tag():
            name = request.json.get("name")
            if not name:
                return (ERR_BAD_REQUEST, "name is required")
            # ... create tag ...
            return (OK, {"id": tag.id, "name": tag.name})
    """

    @wraps(func)
    def wrapper(*args, **kwargs):
        result_type, payload = func(*args, **kwargs)

        if result_type == OK:
            # POST create returns 201; everything else returns 200
            status = 201 if func.__name__ in _CREATED_ROUTES else 200
            return jsonify({"status": "ok", "data": payload}), status
        else:
            status = _STATUS_MAP.get(result_type, 500)
            return jsonify({"status": "error", "message": payload}), status

    return wrapper


# ------------------------------------------------------------------
# Route handlers (pure functions returning result tuples)
# ------------------------------------------------------------------


@tag_bp.route("/tags", methods=["POST"])
@tag_endpoint
def create_tag():
    name = request.json.get("name") if request.is_json else None

    if not name:
        return (ERR_BAD_REQUEST, "name is required")

    if Tag.query.filter_by(name=name).first() is not None:
        return (ERR_CONFLICT, "tag name already exists")

    tag = Tag(name=name)
    db.session.add(tag)
    db.session.commit()

    return (OK, {"id": tag.id, "name": tag.name})


@tag_bp.route("/tags", methods=["GET"])
@tag_endpoint
def list_tags():
    tags = Tag.query.order_by(Tag.id).all()
    data = [{"id": t.id, "name": t.name} for t in tags]
    return (OK, data)


@tag_bp.route("/tags/<int:tag_id>", methods=["PUT"])
@tag_endpoint
def update_tag(tag_id):
    tag = Tag.query.get(tag_id)
    if tag is None:
        return (ERR_NOT_FOUND, "tag not found")

    name = request.json.get("name") if request.is_json else None
    if not name:
        return (ERR_BAD_REQUEST, "name is required")

    existing = Tag.query.filter(Tag.name == name, Tag.id != tag_id).first()
    if existing is not None:
        return (ERR_CONFLICT, "tag name already exists")

    tag.name = name
    db.session.commit()

    return (OK, {"id": tag.id, "name": tag.name})


@tag_bp.route("/tags/<int:tag_id>", methods=["DELETE"])
@tag_endpoint
def delete_tag(tag_id):
    tag = Tag.query.get(tag_id)
    if tag is None:
        return (ERR_NOT_FOUND, "tag not found")

    # Cascade: remove all article-tag associations first
    db.session.execute(
        article_tags.delete().where(article_tags.c.tag_id == tag_id)
    )
    db.session.delete(tag)
    db.session.commit()

    return (OK, {"message": "Tag deleted"})

"""
T2 Blog - Tag Routes (Sample 2: Validation-Helper + Try/Except Strategy)

Implementation approach:
- Centralized validation helper (validate_name) reused across routes
- All DB mutations wrapped in try/except with rollback on failure
- IntegrityError-based duplicate detection (no pre-query needed)
- Explicit tag serializer (tag_to_dict) for consistent response shaping
"""

from flask import Blueprint, request, jsonify
from sqlalchemy.exc import IntegrityError

from app import db
from models import Tag, article_tags

tag_bp = Blueprint('tag_bp', __name__)


def validate_name(payload):
    """Extract and validate the 'name' field from a JSON payload.

    Returns:
        (str, None) on success - the validated name string
        (None, response_tuple) on failure - a Flask error response

    This helper is called by create and update routes to ensure
    consistent input validation logic.
    """
    if not payload or 'name' not in payload:
        return None, (jsonify({"status": "error", "message": "Missing required field: name"}), 400)

    name = payload.get('name', '').strip()
    if not name:
        return None, (jsonify({"status": "error", "message": "Missing required field: name"}), 400)

    return name, None


def tag_to_dict(tag):
    """Serialize a Tag model instance to a plain dict."""
    return {"id": tag.id, "name": tag.name}


@tag_bp.route('/tags', methods=['POST'])
def create_tag():
    name, err = validate_name(request.get_json(silent=True))
    if err:
        return err

    tag = Tag(name=name)
    db.session.add(tag)

    try:
        db.session.commit()
    except IntegrityError:
        db.session.rollback()
        return jsonify({"status": "error", "message": "Tag already exists"}), 409

    return jsonify({"status": "ok", "data": tag_to_dict(tag)}), 201


@tag_bp.route('/tags', methods=['GET'])
def list_tags():
    tags = Tag.query.order_by(Tag.id).all()
    return jsonify({"status": "ok", "data": [tag_to_dict(t) for t in tags]}), 200


@tag_bp.route('/tags/<int:tag_id>', methods=['PUT'])
def update_tag(tag_id):
    tag = Tag.query.get(tag_id)
    if tag is None:
        return jsonify({"status": "error", "message": "Tag not found"}), 404

    name, err = validate_name(request.get_json(silent=True))
    if err:
        return err

    tag.name = name

    try:
        db.session.commit()
    except IntegrityError:
        db.session.rollback()
        return jsonify({"status": "error", "message": "Tag already exists"}), 409

    return jsonify({"status": "ok", "data": tag_to_dict(tag)}), 200


@tag_bp.route('/tags/<int:tag_id>', methods=['DELETE'])
def delete_tag(tag_id):
    tag = Tag.query.get(tag_id)
    if tag is None:
        return jsonify({"status": "error", "message": "Tag not found"}), 404

    try:
        # Cascade-delete all article-tag bindings via the association table
        db.session.execute(
            article_tags.delete().where(article_tags.c.tag_id == tag_id)
        )
        db.session.delete(tag)
        db.session.commit()
    except Exception:
        db.session.rollback()
        return jsonify({"status": "error", "message": "Failed to delete tag"}), 500

    return jsonify({"status": "ok", "data": {"message": "Tag deleted"}}), 200

