"""
T2 Blog - Article Routes (Gen 1 Sample 2: Response-Builder + Context-Manager Strategy)

Implementation approach (deliberately different from routes_tag.py's validation-helper style):

1. ok() / err() - Lightweight response-building closures via functools.partial.
   Instead of returning (name, error_tuple) tuples and branching at every call site,
   each helper returns a Flask-ready response immediately. This keeps route bodies
   flat and avoids multi-return-value unpacking.

2. Context manager (safe_commit) - Wraps db.session.commit() in a try/except with
   automatic rollback. Used as `with safe_commit(): <mutation>`. This separates
   transaction-safety concerns from business logic.

3. model_to_dict() - Generic-ish serializer; article_to_dict() and tag_to_dict()
   are thin wrappers around it, ensuring a uniform serialization surface.

4. Inline validation in each route - No shared validation helper. Each route
   validates its own input inline, keeping the code self-contained and easier
   to reason about in isolation.
"""

from contextlib import contextmanager
from functools import partial
from flask import Blueprint, request, jsonify
from sqlalchemy.exc import IntegrityError

from app import db
from models import Article, Tag, article_tags

article_bp = Blueprint('article_bp', __name__)

# ── Response Builders ────────────────────────────────────────────────────────
# Each returns a Flask response tuple. status_code defaults to 200.

_ok = partial(jsonify, status="ok")
_err = partial(jsonify, status="error")


def ok(data, code=200):
    """Build a success response: {"status": "ok", "data": ...}"""
    return jsonify({"status": "ok", "data": data}), code


def err(message, code=400):
    """Build an error response: {"status": "error", "message": ...}"""
    return jsonify({"status": "error", "message": message}), code


# ── DB Context Manager ───────────────────────────────────────────────────────

@contextmanager
def safe_commit():
    """Context manager that commits on success and rolls back on exception.

    Usage::

        with safe_commit():
            db.session.add(obj)
        # if we reach here, commit succeeded

    If the commit raises an exception, the session is rolled back and the
    exception is re-raised so the caller can handle it.
    """
    try:
        yield
        db.session.commit()
    except Exception:
        db.session.rollback()
        raise


# ── Serializers ───────────────────────────────────────────────────────────────

def model_to_dict(instance, *fields):
    """Generic field-level serializer for SQLAlchemy models.

    Given an ORM instance and a list of field names, returns a dict with
    only those fields. This is the single serialization chokepoint, so
    response shapes are guaranteed consistent.
    """
    return {f: getattr(instance, f) for f in fields}


def article_to_dict(article):
    return model_to_dict(article, 'id', 'title', 'body')


def tag_to_dict(tag):
    return model_to_dict(tag, 'id', 'name')


# ── Routes ───────────────────────────────────────────────────────────────────

@article_bp.route('/articles', methods=['GET'])
def list_articles():
    """GET /articles — List articles, optionally filtered by tag name or tag ID."""
    tag_name = request.args.get('tag')
    tag_id = request.args.get('tag_id', type=int)

    query = Article.query

    if tag_name is not None:
        tag = Tag.query.filter_by(name=tag_name).first()
        if tag is None:
            return ok([])
        query = query.join(article_tags).filter(article_tags.c.tag_id == tag.id)

    elif tag_id is not None:
        query = query.join(article_tags).filter(article_tags.c.tag_id == tag_id)

    articles = query.all()
    return ok([article_to_dict(a) for a in articles])


@article_bp.route('/articles', methods=['POST'])
def create_article():
    """POST /articles — Create a new article."""
    payload = request.get_json(silent=True)

    if not payload or 'title' not in payload or 'body' not in payload:
        return err("Missing required fields: title and body")

    article = Article(title=payload['title'], body=payload['body'])
    db.session.add(article)

    try:
        with safe_commit():
            pass  # commit happens in the context manager exit
    except IntegrityError:
        return err("Failed to create article", 409)

    return ok(article_to_dict(article), 201)


@article_bp.route('/articles/<int:article_id>', methods=['GET'])
def get_article(article_id):
    """GET /articles/<id> — Retrieve a single article by ID."""
    article = Article.query.get(article_id)
    if article is None:
        return err("Article not found", 404)
    return ok(article_to_dict(article))


@article_bp.route('/articles/<int:article_id>/tags', methods=['GET'])
def get_article_tags(article_id):
    """GET /articles/<id>/tags — List all tags bound to an article."""
    article = Article.query.get(article_id)
    if article is None:
        return err("Article not found", 404)

    return ok([tag_to_dict(t) for t in article.tags])


@article_bp.route('/articles/<int:article_id>/tags', methods=['POST'])
def bind_tags(article_id):
    """POST /articles/<id>/tags — Bind one or more tags to an article.

    Accepts {"tag_ids": [1, 2, ...]}. Silently skips already-bound tags.
    """
    article = Article.query.get(article_id)
    if article is None:
        return err("Article not found", 404)

    payload = request.get_json(silent=True)
    if not payload or 'tag_ids' not in payload:
        return err("Missing required field: tag_ids")

    tag_ids = payload['tag_ids']
    if not isinstance(tag_ids, list):
        return err("tag_ids must be a list")

    # Resolve tag objects; fail fast if any ID doesn't exist
    tags = []
    for tid in tag_ids:
        tag = Tag.query.get(tid)
        if tag is None:
            return err(f"Tag {tid} not found")
        tags.append(tag)

    # Append new tags (SQLAlchemy set semantics skip duplicates automatically)
    for tag in tags:
        article.tags.append(tag)

    try:
        with safe_commit():
            pass
    except Exception:
        return err("Failed to bind tags", 500)

    return ok({"message": "Tags bound"})


@article_bp.route('/articles/<int:article_id>/tags/<int:tag_id>', methods=['DELETE'])
def unbind_tag(article_id, tag_id):
    """DELETE /articles/<id>/tags/<tag_id> — Remove a tag-article binding."""
    article = Article.query.get(article_id)
    if article is None:
        return err("Article not found", 404)

    tag = Tag.query.get(tag_id)
    if tag is not None and tag in article.tags:
        article.tags.remove(tag)

        try:
            with safe_commit():
                pass
        except Exception:
            return err("Failed to unbind tag", 500)

    return ok({"message": "Tag unbound"})

"""
T2 Blog -- Article Routes (Sample 1: Decorator-Based Error Handling Strategy)

Implementation approach:
- Custom @catch_db_errors decorator wraps all mutating routes for unified
  transaction safety (rollback on any exception).
- Centralized article serializer (article_to_dict) for consistent shaping.
- Article existence is resolved via a reusable _find_article() helper that
  returns (article, error_response) -- similar to the tag validation pattern
  but adapted for lookup rather than input validation.
- Tag-binding routes use bulk insert via association table with conflict
  handling through IntegrityError capture.
- Filtering supports both ?tag=<name> and ?tag_id=<id> via a single
  _build_filtered_query() factory, keeping list-article logic DRY.

Response contract:
  Success: {"status": "ok", "data": ...}
  Error:   {"status": "error", "message": "..."}
"""

from functools import wraps
from flask import Blueprint, request, jsonify
from sqlalchemy.exc import IntegrityError

from app import db
from models import Article, Tag, article_tags

article_bp = Blueprint('article_bp', __name__)


# ------------------------------------------------------------------ #
#  Decorator: catch_db_errors
# ------------------------------------------------------------------ #

def catch_db_errors(f):
    """Decorator: wrap a route handler in try/except with session rollback.

    If the wrapped function raises any exception, the DB session is rolled
    back and a generic 500 error is returned.  IntegrityError is mapped to
    409.  The decorator is intentionally kept simple -- it does NOT catch
    validation errors (those are returned as normal response tuples before
    any DB write happens).
    """
    @wraps(f)
    def wrapper(*args, **kwargs):
        try:
